#include <bits/stdc++.h>
using namespace std;

int a[1000005];

int main() {
    char ch;
    int len = 0;
    while (cin >> ch) {
        if (isdigit(ch)) {
            a[len++] = ch - '0';
        }
    }
    sort(a, a + len);
    for (int i = len - 1; i >= 0; i--) {
        cout << a[i];
    }
    return 0;
}
